changeSet.sql:
CREATE TABLE config_audit_event ( id BIGSERIAL PRIMARY KEY, occurred_at TIMESTAMPTZ NOT NULL DEFAULT now(), workspace_id BIGINT NOT NULL CONSTRAINT sfk_config_audit_event_workspace_id REFERENCES workspace(id), actor_kind VARCHAR(16) NOT NULL, actor_account_id BIGINT CONSTRAINT sfk_config_audit_event_actor_account_id REFERENCES account(id) ON DELETE SET NULL, acting_account_id BIGINT CONSTRAINT sfk_config_audit_event_acting_account_id REFERENCES account(id) ON DELETE SET NULL, entity_type VARCHAR(48) NOT NULL, entity_id VARCHAR(64) NOT NULL, action VARCHAR(16) NOT NULL, changed_keys TEXT[] NOT NULL, old_value JSONB, new_value JSONB, CONSTRAINT ck_config_audit_event_actor_kind CHECK (actor_kind IN ('USER', 'SYSTEM', 'IMPERSONATED')), CONSTRAINT ck_config_audit_event_action CHECK (action IN ('CREATED', 'UPDATED', 'DELETED')), CONSTRAINT ck_config_audit_event_entity_type CHECK (entity_type IN ('PRACTICE_REVIEW_SETTINGS', 'AI_CONFIG_BINDING', 'AGENT_CONFIG')) -- Deliberately NO "old_value IS NOT NULL OR new_value IS NOT NULL" constraint. It reads -- like a useful invariant (a row with neither describes nothing) but it would forbid the -- one UPDATE changeset -2 exists to permit: erasure NULLs both snapshots, so the check -- would make the table architecturally incapable of honouring GDPR Art. 17 — and no test -- would catch it, since context="prod" means the suite never loads either object. The -- invariant belongs at the write path instead, where it can be enforced without -- outlawing erasure: ConfigAuditEntry's constructor rejects an entry with neither side. );
-- workspace_id FK is deliberately NO ACTION, not CASCADE: CASCADE would hand anyone with -- delete rights a one-click audit eraser, and the cascaded DELETE would hit the changeset -2 -- trigger and abort the workspace deletion in prod only (FK referential actions fire -- triggers — PG 37.1). Moot in practice: WorkspaceLifecycleService soft-deletes to PURGED. -- The account FKs are ON DELETE SET NULL, and changeset -2's per-column erasure carve-out -- permits exactly that single-column nulling, so the FK action and the trigger agree instead -- of deadlocking. Moot today regardless: AccountPurger tombstones rather than deleting, and -- the tombstone is what de-identifies actor_account_id.
-- Per-resource and per-control history (#1357): the settings pages filter by entity, then -- by changed key. CREATE INDEX ix_config_audit_event_entity ON config_audit_event (workspace_id, entity_type, entity_id, occurred_at DESC, id DESC);
-- Workspace timeline. CREATE INDEX ix_config_audit_event_workspace_occurred ON config_audit_event (workspace_id, occurred_at DESC, id DESC);

REVOKE UPDATE, TRUNCATE ON config_audit_event FROM CURRENT_USER;
CREATE OR REPLACE FUNCTION config_audit_event_block_mutation() RETURNS trigger AS $cfg_immut$ BEGIN IF TG_OP = 'DELETE' THEN -- Retention is the ONLY sanctioned delete (ConfigAuditRetentionJob, 365 days). -- Keeping the window here rather than blocking DELETE outright is what lets this -- table stay unpartitioned while still honouring storage limitation (GDPR Art. -- 5(1)(e)). Inside the window the row is untouchable. IF OLD.occurred_at >= now() - interval '365 days' THEN RAISE EXCEPTION 'config_audit_event is append-only: DELETE is only permitted past the 365-day retention window'; END IF; RETURN OLD; END IF; -- Permit ONLY erasure, per column: each redactable column may stay as it is or go to -- NULL, and nothing else about the row may change. Comparing the whole row MINUS the -- redactable columns (to_jsonb - keys) is column-addition-proof — a future column is -- automatically protected with no edit here. -- -- Per-column rather than all-four-at-once, which is what this originally demanded. That -- version was wrong twice over: (a) an FK's ON DELETE SET NULL updates only ITS OWN -- column (PG CREATE TABLE), so a hard account delete would null actor_account_id, leave -- the snapshots populated, trip this branch and abort the delete — the FK/trigger -- deadlock this carve-out exists to avoid; and (b) redacting a toxic snapshot would have -- forced nulling the actor refs too, destroying the attribution that is the one thing -- GDPR does not ask us to erase and the whole reason this table exists. -- -- Nulling only the actor is therefore reachable. That is not a weakening: under the -- stated threat model (application bugs and misconfigured grants — not the operator, who -- is the DBA and can DISABLE TRIGGER anyway) anything that can reach UPDATE could -- previously null EVERYTHING, which destroys strictly more. IF (NEW.actor_account_id IS NULL OR NEW.actor_account_id = OLD.actor_account_id) AND (NEW.acting_account_id IS NULL OR NEW.acting_account_id = OLD.acting_account_id) AND (NEW.old_value IS NULL OR NEW.old_value = OLD.old_value) AND (NEW.new_value IS NULL OR NEW.new_value = OLD.new_value) AND (to_jsonb(NEW) - 'actor_account_id' - 'acting_account_id' - 'old_value' - 'new_value') IS NOT DISTINCT FROM (to_jsonb(OLD) - 'actor_account_id' - 'acting_account_id' - 'old_value' - 'new_value') THEN RETURN NEW; END IF; RAISE EXCEPTION 'config_audit_event is append-only: only erasure (setting actor refs / snapshots to NULL) is permitted'; END; $cfg_immut$ LANGUAGE plpgsql;
CREATE TRIGGER trg_config_audit_event_block_mutation BEFORE UPDATE OR DELETE ON config_audit_event FOR EACH ROW EXECUTE FUNCTION config_audit_event_block_mutation();
CREATE OR REPLACE FUNCTION config_audit_event_block_truncate() RETURNS trigger AS $cfg_trunc$ BEGIN RAISE EXCEPTION 'config_audit_event is append-only: TRUNCATE is not permitted'; END; $cfg_trunc$ LANGUAGE plpgsql;
CREATE TRIGGER trg_config_audit_event_block_truncate BEFORE TRUNCATE ON config_audit_event FOR EACH STATEMENT EXECUTE FUNCTION config_audit_event_block_truncate();

rollback.sql:
DROP TRIGGER IF EXISTS trg_config_audit_event_block_truncate ON config_audit_event;
DROP TRIGGER IF EXISTS trg_config_audit_event_block_mutation ON config_audit_event;
DROP FUNCTION IF EXISTS config_audit_event_block_truncate();
DROP FUNCTION IF EXISTS config_audit_event_block_mutation();
GRANT UPDATE, TRUNCATE ON config_audit_event TO CURRENT_USER;
